import { SeriesBaseStrategy } from './base-series.js';
import { GappableSeriesHelper } from './gappable-series.js';
import { StackableSeriesHelper } from './stackable-series.js';
import type { Orientation } from '../../../core/components/canvas/types/canvas-shape.js';
import { isValidPointsDisplay } from '../../../core/components/canvas/utils/is-valid-points-display.js';
import { safeGet } from '../../../core/utils/safe-get.js';
import { DEFAULT_POINTS_DISPLAY } from '../../constants/defaults.js';
import type {
  AnyDatapoint,
  AreaSeriesWithDatapoints,
  AxisId,
  DatapointMetadata,
  SeriesId,
  XYChartAreaSeriesInternal,
  XYChartAreaVariant,
  XYChartAxisInternal,
  XYChartOrientation,
  XYChartVariantsInternal,
} from '../../types/xy-chart-internals.js';
import type { XYChartSelectionLinearMetadata } from '../../types/xy-chart-selection.js';
import type {
  AreaDatapoint,
  XYChartColorPalette,
  XYChartData,
} from '../../types/xy-chart.js';
import { isAreaSeries } from '../../utils/type-guards.js';
import type {
  AreaSeriesConstructor,
  ControlFlowCommand,
  MutableProcessingContext,
} from '../types/processing-types.js';
import { getAreaDatapoints } from '../utils/access-datapoint/get-area-datapoints.js';
import {
  getChartAreaVariant,
  getChartOrientation,
  getDatumValue,
} from '../utils/access-datapoint/get-datapoints.js';
import { getCalculatedLinearPointForArea } from '../utils/cast-data/get-calculated-linear-point.js';
import { getLinearColor } from '../utils/coloring/get-linear-color-palette.js';
import { isAreaSeriesStacked } from '../utils/stacking/is-area-series-stacked.js';
import {
  getBaselineCoordinate,
  getCombinedAxesOrientationKey,
  isStackable,
} from '../utils/stacking/stack-datapoints.js';

export class AreaSeriesStrategy extends SeriesBaseStrategy<XYChartSelectionLinearMetadata> {
  private readonly stackHelper: StackableSeriesHelper;
  private readonly gapHelper: GappableSeriesHelper<AreaDatapoint>;
  /**
   * This is needed for special cases such as isolated points in value representation in area charts.
   */
  public readonly combinedAxesOrientationKeyToSeriesCount: Map<string, number>;
  /** This set contains series Id that has been preprocessed at least once */
  private readonly preprocessedSeriesIds: Set<SeriesId>;

  constructor(initializer: AreaSeriesConstructor) {
    super(initializer);
    this.stackHelper = new StackableSeriesHelper();
    this.gapHelper = new GappableSeriesHelper();
    this.combinedAxesOrientationKeyToSeriesCount = new Map();
    this.preprocessedSeriesIds = new Set();
  }
  canHandle(
    seriesProps: XYChartVariantsInternal,
  ): seriesProps is XYChartAreaSeriesInternal {
    return isAreaSeries(seriesProps);
  }

  protected getSeriesId(
    datum: XYChartData,
    seriesProps: XYChartAreaSeriesInternal,
  ): string {
    return getDatumValue(
      datum,
      seriesProps.seriesIdAccessor,
    )?.toString() as string;
  }

  protected createSeries(
    seriesId: string,
    seriesProps: XYChartAreaSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
  ) {
    return {
      id: seriesId,
      type: seriesProps.type,
      data: [],
      xAxisId: xAxis.id,
      yAxisId: yAxis.id,
    };
  }

  protected createSeriesMetadata(
    datum: XYChartData,
    seriesProps: XYChartAreaSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    seriesId: string,
    context: MutableProcessingContext,
  ) {
    const { intl, seriesIndexes } = context;
    const { nameAccessor: seriesNameAccessor, curve } = seriesProps;

    const seriesIndex = this.getOrCreateSeriesIndex(seriesId, seriesIndexes);
    const seriesName = this.getSeriesName(intl, seriesIndex, undefined, {
      seriesNameAccessor,
      datum,
    });

    const color = this.getColor(
      datum,
      seriesProps,
      context.colorPalette,
      seriesName,
      seriesIndex,
    );

    // Determine orientation based on accessors
    const chartOrientation = getChartOrientation(seriesProps);
    const orientation: Orientation =
      chartOrientation === 'horizontal' ? 'horizontal' : 'vertical';

    const variant = getChartAreaVariant(
      chartOrientation as XYChartOrientation,
      seriesProps,
    );

    return {
      xAxis,
      yAxis,
      ...color,
      name: seriesName,
      orientation,
      curve,
      variant,
      pointsDisplay:
        seriesProps.pointsDisplay &&
        isValidPointsDisplay(seriesProps.pointsDisplay)
          ? seriesProps.pointsDisplay
          : DEFAULT_POINTS_DISPLAY,
      actions: seriesProps.actions,
    };
  }

  protected getCalculationPoint(
    datapoint: AreaDatapoint,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    chartOrientation?: XYChartOrientation,
    variant?: XYChartAreaVariant,
  ) {
    return getCalculatedLinearPointForArea(
      datapoint,
      xAxis,
      yAxis,
      chartOrientation,
      variant,
    );
  }

  protected preprocessImpl(
    data: XYChartData[],
    seriesProps: XYChartAreaSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    context: MutableProcessingContext,
  ): ControlFlowCommand {
    const chartOrientation = getChartOrientation(seriesProps);
    if (chartOrientation === undefined || chartOrientation === 'both') {
      return;
    }

    const areaVariant = getChartAreaVariant(chartOrientation, seriesProps);

    // Band areas don't stack, so skip preprocessing
    if (areaVariant === 'band') {
      return;
    }

    const canStack = isStackable('stack', chartOrientation, xAxis, yAxis);

    if (!canStack) {
      return;
    }

    const filteredSeriesIds = context?.filteredSeriesIds;

    for (const datum of data) {
      const datapoint = this.getDatapoint(datum, seriesProps, xAxis, yAxis);

      const variant = getChartAreaVariant(chartOrientation, seriesProps);

      if (datapoint) {
        const seriesId = this.getSeriesId(datum, seriesProps);

        const isSeriesVisible =
          filteredSeriesIds === undefined || filteredSeriesIds.has(seriesId);

        if (!isSeriesVisible) {
          continue;
        }

        this.registerSeriesCountOnPreprocessing(
          seriesId,
          xAxis.id,
          yAxis.id,
          chartOrientation,
        );

        const preCalcPoint = this.getCalculationPoint(
          datapoint,
          xAxis,
          yAxis,
          chartOrientation,
          variant,
        );

        this.stackHelper.processStackDomain(
          preCalcPoint,
          chartOrientation,
          xAxis,
          yAxis,
          seriesId,
        );
      }
    }
  }

  protected processImpl(
    datum: XYChartData,
    seriesProps: XYChartAreaSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    datapoint: AreaDatapoint,
    context: MutableProcessingContext,
  ) {
    const { seriesMap, seriesToMetadata } = context;

    const seriesId = this.getSeriesId(datum, seriesProps);
    const isSeriesVisible =
      context.filteredSeriesIds === undefined ||
      context.filteredSeriesIds.has(seriesId);

    const chartOrientation = getChartOrientation(seriesProps);

    if (!chartOrientation) {
      return 'continue';
    }

    const variant = getChartAreaVariant(chartOrientation, seriesProps);

    // doing this first cause we want to stack the start/end (middle) and the center when are the same
    const preCalcPoint = this.getCalculationPoint(
      datapoint,
      xAxis,
      yAxis,
      chartOrientation,
      variant,
    );

    let calcDatapoint: AnyDatapoint;
    let datapointMetadata: DatapointMetadata;
    let shouldContinue: boolean;

    if (isSeriesVisible) {
      ({ calcDatapoint, datapointMetadata, shouldContinue } =
        this.handleStacking(
          preCalcPoint,
          xAxis,
          yAxis,
          chartOrientation,
          variant,
        ));
    } else {
      calcDatapoint = preCalcPoint;
      datapointMetadata = {
        isGap: false,
        baseline: getBaselineCoordinate(chartOrientation),
      };
      shouldContinue = false;
    }

    if (shouldContinue) {
      return 'continue';
    }

    let currentSeries: AreaSeriesWithDatapoints | undefined =
      seriesMap.get(seriesId);

    if (!currentSeries) {
      currentSeries = this.createSeries(seriesId, seriesProps, xAxis, yAxis);

      this.registerSeries(currentSeries, seriesId, context);

      const metadata = this.createSeriesMetadata(
        datum,
        seriesProps,
        xAxis,
        yAxis,
        seriesId,
        context,
      );

      seriesToMetadata.set(currentSeries, {
        ...metadata,
        isVisible: isSeriesVisible,
        isStacked:
          chartOrientation !== 'both' &&
          isAreaSeriesStacked(
            getCombinedAxesOrientationKey(xAxis.id, yAxis.id, chartOrientation),
            this.combinedAxesOrientationKeyToSeriesCount,
            variant,
          ),
      });
    }

    const currentSeriesMetadata = safeGet(seriesToMetadata, currentSeries);

    if (isSeriesVisible) {
      context.axisWithSeries.add(xAxis.id);
      context.axisWithSeries.add(yAxis.id);

      const gappedDatapoint = this.gapHelper.handleGapDetection(
        datapoint,
        currentSeries,
        xAxis,
        yAxis,
      );

      if (gappedDatapoint) {
        this.registerDatapoint(
          gappedDatapoint,
          { isGap: true },
          currentSeries,
          context,
        );
      }
    }

    this.registerDatapoint(
      datapoint,
      datapointMetadata,
      currentSeries,
      context,
    );

    this.updateAxisDomains(
      calcDatapoint,
      xAxis,
      yAxis,
      context.axisIdToScaleDomain,
      isSeriesVisible,
    );

    if (isSeriesVisible) {
      this.addValue({
        series: currentSeries,
        datapoint,
        color: currentSeriesMetadata?.color,
      });
    }
  }

  getColor(
    datum: XYChartData,
    seriesProps: XYChartAreaSeriesInternal,
    configColorPalette: XYChartColorPalette | undefined,
    seriesName: string,
    seriesIndex: number,
  ) {
    //TODO: add color in APPDEV-15003
    return getLinearColor(
      datum,
      seriesProps,
      configColorPalette,
      seriesName,
      seriesIndex,
    );
  }

  getDatapoint(
    datum: XYChartData,
    seriesProps: XYChartAreaSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
  ) {
    return getAreaDatapoints(datum, seriesProps, xAxis, yAxis);
  }

  private handleStacking(
    datapoint: AreaDatapoint,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    chartOrientation: XYChartOrientation,
    areaVariant: XYChartAreaVariant,
  ) {
    if (areaVariant === 'band') {
      return {
        calcDatapoint: datapoint,
        datapointMetadata: {
          isGap: false,
          baseline: getBaselineCoordinate(chartOrientation),
        },
        shouldContinue: false,
      };
    }

    let calcDatapoint: AnyDatapoint | undefined;
    let shouldContinue = false;
    let datapointMetadata: DatapointMetadata = {
      isGap: false,
      baseline: getBaselineCoordinate(chartOrientation),
    };

    const canStack = isStackable('stack', chartOrientation, xAxis, yAxis);

    if (canStack) {
      ({ calcDatapoint, datapointMetadata, shouldContinue } =
        this.stackHelper.processStackedDatapoint(
          datapoint,
          chartOrientation as 'vertical' | 'horizontal',
          xAxis,
          yAxis,
          datapointMetadata,
        ));
    }

    return {
      calcDatapoint: calcDatapoint ?? datapoint,
      datapointMetadata,
      shouldContinue,
    };
  }

  private registerSeriesCountForAxisCombination(
    xAxisId: AxisId,
    yAxisId: AxisId,
    chartOrientation: Orientation,
  ) {
    const axesCombinationKey = getCombinedAxesOrientationKey(
      xAxisId,
      yAxisId,
      chartOrientation,
    );
    const count =
      this.combinedAxesOrientationKeyToSeriesCount.get(axesCombinationKey) ?? 0;
    this.combinedAxesOrientationKeyToSeriesCount.set(
      axesCombinationKey,
      count + 1,
    );
  }

  private registerSeriesCountOnPreprocessing(
    seriesId: SeriesId,
    xAxisId: string,
    yAxisId: string,
    chartOrientation: Orientation,
  ) {
    if (!this.preprocessedSeriesIds.has(seriesId)) {
      this.registerSeriesCountForAxisCombination(
        xAxisId,
        yAxisId,
        chartOrientation,
      );
      this.preprocessedSeriesIds.add(seriesId);
    }
  }
}
